// Auth + payload validation.
const token = $input.first().headers['x-carbonsense-token'];
if (!token || token !== $env.CARBONSENSE_SHARED_SECRET) {
  throw new Error('Unauthorized');
}

const b = $input.first().json.body || $input.first().json;
const required = ['area_id', 'area_name', 'sector', 'coordinates', 'emissions_summary'];
for (const k of required) {
  if (b[k] === undefined || b[k] === null) {
    throw new Error(`Missing field: ${k}`);
  }
}

// Build the retrieval query text. Embedding lat/lng is meaningless; the
// semantic signal comes from the area name + sector + risk flags + dominant
// source pulled out of emissions_summary.
const uc = b.emissions_summary?.uc_data || {};
const tflags = (uc.transport?.risk_flags || []).join(', ');
const bflags = (uc.buildings?.risk_flags || []).join(', ');
const sectorBlock = uc[b.sector] || {};
const dominant = sectorBlock.dominant_source || sectorBlock.risk_level || '';

const query = (
  `${b.sector} emission reduction strategies for ${b.area_name} Union Council, ` +
  `Lahore District, Punjab, Pakistan. ` +
  `Sector intensity ${sectorBlock.intensity_t_per_km2 || sectorBlock.intensity_t_km2 || 'n/a'} t/km². ` +
  `Risk flags: ${tflags || bflags || 'none'}. ` +
  `Dominant driver: ${dominant || 'unspecified'}. ` +
  `Looking for proven interventions, policy levers, and monitoring metrics.`
);

return [{ json: { ...b, retrieval_query: query } }];

// Re-rank: dedupe policy chunks by url, boost geo=lahore/punjab, always
// keep the user's UC's own data chunk, cap at 5 policy + 3 data.
const rows = $input.first().json || [];
const payload = $('Validate + build query').first().json;
const targetUc = (payload.area_name || '').toLowerCase().trim();

const policy = [];
const data = [];
const seenUrls = new Set();

const boost = (row) => {
  let s = row.similarity;
  const geo = row.meta?.geo;
  if (geo === 'lahore' || geo === 'punjab') s += 0.15;
  return s;
};

for (const r of rows) {
  if (r.source === 'policy') {
    const url = r.meta?.url;
    if (url && seenUrls.has(url)) continue;
    if (url) seenUrls.add(url);
    if (r.similarity < 0.35) continue;
    policy.push({ ...r, _boosted: boost(r) });
  } else if (r.source === 'data') {
    data.push(r);
  }
}

policy.sort((a, b) => b._boosted - a._boosted);

// Make sure the UC's own row is present even if low-similarity
const hasOwn = data.some(r => (r.meta?.uc || '').toLowerCase().trim() === targetUc);
if (!hasOwn) {
  // fall through — the data block will list peer UCs instead
}

const topPolicy = policy.slice(0, 5);
const topData = data.slice(0, 3);

// Truncate long chunks to ~250 tokens (~1000 chars) at sentence boundary
const trim = (txt, max = 1000) => {
  if (!txt || txt.length <= max) return txt;
  const cut = txt.lastIndexOf('. ', max);
  return (cut > 200 ? txt.slice(0, cut + 1) : txt.slice(0, max)) + ' […]';
};

const dataBlock = topData.map((r, i) => 
  `[D${i + 1}] ${r.meta?.uc || 'aggregate'} — ${r.meta?.type}:\n${trim(r.chunk_text, 1200)}`
).join('\n\n');

const policyBlock = topPolicy.map((r, i) =>
  `[P${i + 1}] ${r.meta?.title || 'untitled'} — ${r.meta?.org || 'unknown source'} (similarity ${r.similarity.toFixed(2)})\n"""\n${trim(r.chunk_text)}\n"""`
).join('\n\n');

const retrievedIds = {
  policy: topPolicy.map(r => r.id),
  data: topData.map(r => r.id),
};

return [{ json: { ...payload, dataBlock, policyBlock, retrievedIds } }];

// Compose the prompt. Static blocks (system, frameworks) carry
// `cache_control: ephemeral` so Anthropic prompt caching kicks in.

const p = $input.first().json;
const summary = p.emissions_summary || {};
const uc = summary.uc_data || {};
const t = uc.transport || {};
const b = uc.buildings || {};
const w = uc.waste || {};

const num = (v, d = '—') => (typeof v === 'number' && isFinite(v)) ? v.toLocaleString('en-US', { maximumFractionDigits: 0 }) : d;

const baseline = [
  `Union Council: ${p.area_name} (Lahore District, Punjab, Pakistan)`,
  `Coordinates: ${p.coordinates?.lat}, ${p.coordinates?.lng}`,
  `Primary sector for analysis: ${p.sector}`,
  ``,
  t.forecast_annual_t ? `Transport: ${num(t.forecast_annual_t)} t CO2e/yr (road ${t.road_pct || 0}%, intensity ${num(t.intensity_t_per_km2)} t/km², rank #${t.rank_in_division || '?'}/151, flags: ${(t.risk_flags || []).join(', ') || 'none'})` : null,
  b.forecast_total_t ? `Buildings: ${num(b.forecast_total_t)} t CO2e/yr (residential ${num(b.residential_t)} t, non-residential ${num(b.non_residential_t)} t, intensity ${num(b.intensity_t_km2)} t/km², rank #${b.rank_in_district || '?'}/151)` : null,
  w.forecast_annual_t ? `Waste: ${num(w.forecast_annual_t)} t CO2e/yr (point sources ${w.point_pct || 0}%, risk level ${w.risk_level || 'unknown'})` : null,
  ``,
  `Trend: ${summary.trend_direction || 'unknown'} (${(summary.trend_percentage || 0).toFixed(1)}% vs historical baseline)`,
].filter(Boolean).join('\n');

const SYSTEM = `You are a senior climate policy advisor to the Government of Punjab, specializing in Pakistan urban emission reduction. You produce site-specific action plans grounded in retrieved evidence (policy documents + local emission data). You cite [P#] for policy claims and [D#] for data claims. You never invent statute sections or numbers — only quote what appears in the retrieved evidence.`;

const FRAMEWORKS = `═══ INTERNATIONAL FRAMEWORKS TO ANCHOR IN ═══
- Paris Agreement Art. 4 (NDC alignment)
- IPCC AR6 WG3 Ch.10 (transport) / Ch.9 (buildings) / Ch.11 (waste)
- C40 Climate Action Planning Framework
- SBTi targets for sub-national entities
- UN-Habitat Global Urban Monitoring Framework
- WHO Air Quality Guidelines (PM2.5)

Generate the response as STRICT JSON with these six keys: summary, immediate_actions (5 items), long_term_strategies (3-4 items), policy_recommendations (3-4 items, each citing a [P#] source), monitoring_metrics (3-4 items, UC-level measurable), risk_factors (3-4 items). Each strategy must cite at least one [P#] and one framework above. Quantify against the baseline numbers. Return ONLY the JSON object — no markdown fences, no preface.`;

const body = {
  model: 'anthropic/claude-sonnet-4-6',
  provider: { order: ['Anthropic'], allow_fallbacks: false },
  max_tokens: 1800,
  temperature: 0.4,
  response_format: { type: 'json_object' },
  messages: [
    {
      role: 'system',
      content: [{ type: 'text', text: SYSTEM, cache_control: { type: 'ephemeral' } }]
    },
    {
      role: 'user',
      content: [
        { type: 'text', text: FRAMEWORKS, cache_control: { type: 'ephemeral' } },
        { type: 'text', text: `═══ LOCAL DATA (from CarbonSense datasets) ═══\n${p.dataBlock || '(no data chunks retrieved)'}\n\n═══ POLICY EVIDENCE (retrieved) ═══\n${p.policyBlock || '(no policy chunks retrieved — generation will rely on frameworks above)'}` },
        { type: 'text', text: `═══ BASELINE FOR ${p.area_name.toUpperCase()} ═══\n${baseline}\n\nReturn ONLY the six-key JSON object now.` }
      ]
    }
  ]
};

return [{ json: { ...p, openrouter_body: body } }];

// Parse, validate schema, assemble final response.
const llm = $input.first().json;
const raw = llm.choices?.[0]?.message?.content || '';

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  // Strip code fences if model added them
  const cleaned = raw.replace(/^```(json)?/, '').replace(/```$/, '').trim();
  parsed = JSON.parse(cleaned);
}

const required = ['summary', 'immediate_actions', 'long_term_strategies', 'policy_recommendations', 'monitoring_metrics', 'risk_factors'];
for (const k of required) {
  if (parsed[k] === undefined) throw new Error(`Missing key in LLM output: ${k}`);
  if (k !== 'summary' && !Array.isArray(parsed[k])) parsed[k] = [];
}

const ctx = $('Re-rank + build evidence blocks').first().json;
const usage = llm.usage || {};

return [{
  json: {
    success: true,
    query: {
      area_id: ctx.area_id,
      area_name: ctx.area_name,
      sector: ctx.sector,
      coordinates: ctx.coordinates,
    },
    recommendations: parsed,
    confidence: {
      overall: 0.85,
      evidence_strength: Math.min(0.95, (ctx.retrievedIds?.policy?.length || 0) / 5),
      data_completeness: Math.min(1.0, (ctx.retrievedIds?.data?.length || 0) / 3),
      geographic_relevance: 0.9,
    },
    source: 'n8n-rag',
    llm_model: 'anthropic/claude-sonnet-4-6',
    retrieved_chunk_ids: ctx.retrievedIds?.policy || [],
    retrieved_data_chunk_ids: ctx.retrievedIds?.data || [],
    usage: { input_tokens: usage.prompt_tokens, output_tokens: usage.completion_tokens },
    generated_at: new Date().toISOString(),
  }
}];

// Stamp run_id from Supabase insert response and return final payload.
const inserted = Array.isArray($input.first().json) ? $input.first().json[0] : $input.first().json;
const run = $('Parse + validate JSON').first().json;
return [{ json: { ...run, run_id: inserted.id, from_cache: false } }];
